public class Team {
  private readonly List<string> _members = new List<string>();
  public IReadOnlyList<string> Members => _members.AsReadOnly();

  public void AddMember(string member) {
    if (!_members.Contains(member)) _members.Add(member);
  }
}

UNIT_TEST_EXAMPLE:
[TestMethod]
public void AddMember_AddsUniqueMember() {
  var team = new Team();
  team.AddMember("alice");
  team.AddMember("alice");
  Assert.AreEqual(1, team.Members.Count);
}

[TestMethod]
public void Members_IsReadOnlyView() {
  var team = new Team();
  team.AddMember("bob");
  Assert.AreEqual("bob", team.Members[0]);
}
